namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        for (int i = 0; i < 5; i++)
        {
            _notifications.Add(new Notification(
                _nextId++,
                $"Welcome notification #{i + 1}",
                DateTime.UtcNow.AddMinutes(-10 + i)));
        }
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns only notifications with Id greater than the given value.</summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>Simulates new notifications arriving over time (called by a background hosted service).</summary>
    public void AddRandom()
    {
        lock (_lock)
        {
            _notifications.Add(new Notification(
                _nextId,
                $"New event at {DateTime.UtcNow:T} (#{_nextId})",
                DateTime.UtcNow));
            _nextId++;
        }
    }
}

namespace NotificationsApp.Services;

/// <summary>
/// Background service that periodically adds fake notifications to simulate
/// real-time data arriving on the server.
/// </summary>
public class NotificationGeneratorService : BackgroundService
{
    private readonly NotificationService _notifications;

    public NotificationGeneratorService(NotificationService notifications)
    {
        _notifications = notifications;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(7), stoppingToken);
            _notifications.AddRandom();
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationSvc

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @n.Message
                <small class="text-muted">@n.Timestamp.ToString("T")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationsApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    // Called during both prerender and interactive render.
    protected override void OnInitialized()
    {
        // Load initial data — this populates the server-rendered HTML.
        _notifications = NotificationSvc.GetAll();
        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    // Called only once after the component is interactive (not during prerender).
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            if (ct.IsCancellationRequested) break;

            var newer = NotificationSvc.GetSince(_lastSeenId);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _lastSeenId = newer.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

